mapper.select:
SELECT q.id, q.category_id as categoryId, c.name as categoryName, q.title, q.answer_key as answerKey, q.expand_knowledge as expandKnowledge, q.difficulty, q.view_count as viewCount FROM question q LEFT JOIN question_category c ON q.category_id = c.id WHERE q.status = 1
AND q.category_id = #{categoryId}
ORDER BY q.created_at DESC
